using namespace UNITREE_LEGGED_SDK;

class Custom
{
public:
    Custom(uint8_t level): safe(LeggedType::Aliengo), udp(level){
        udp.InitCmdData(cmd);
    }
    void UDPRecv();
    void UDPSend();
    void RobotControl();

    Safety safe;
    UDP udp;
    LowCmd cmd = {0};
    LowState state = {0};
    int Tpi = 0;
    int motiontime = 0;
    float dt = 0.002;     // 0.001~0.01
};

void Custom::UDPRecv()
{
    udp.Recv();
}

void Custom::UDPSend()
{  
    udp.Send();
}

void Custom::RobotControl() 
{
    motiontime++;
    udp.GetRecv(state);

    // gravity compensation
    cmd.motorCmd[FR_0].tau = -0.65f;
    cmd.motorCmd[FL_0].tau = +0.65f;
    cmd.motorCmd[RR_0].tau = -0.65f;
    cmd.motorCmd[RL_0].tau = +0.65f;

    if( motiontime >= 500){
        float speed = 1 * sin(3*M_PI*Tpi/1000.0);

        cmd.motorCmd[FL_2].q = PosStopF;
        cmd.motorCmd[FL_2].dq = speed;
        cmd.motorCmd[FL_2].Kp = 0;
        cmd.motorCmd[FL_2].Kd = 4;
        cmd.motorCmd[FL_2].tau = 0.0f;
        Tpi++;
    }

    if(motiontime > 10){
        safe.PowerProtect(cmd, state, 1);
        safe.PositionProtect(cmd, state, 0.087);
    }

    udp.SetSend(cmd);
}

